async (params, browser) => {
  // Open Goodreads search
  await browser.open(`https://www.goodreads.com/search?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('table.tableList, .searchResults, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('table.tableList tr, .searchResults tr, [itemtype*="Book"]').forEach((el, i) => { if (i < 15) { const titleEl = el.querySelector('a.bookTitle, [itemprop="name"] a'); const authorEl = el.querySelector('a.authorName, [itemprop="author"]'); const ratingEl = el.querySelector('.minirating, .greyText, [class*="rating"]'); if (titleEl) { results.push({ title: titleEl.textContent?.trim() || '', url: titleEl.href || '', author: authorEl?.textContent?.trim() || '', rating: ratingEl?.textContent?.trim() || '' }); } } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
